import { useState, useEffect } from 'react';
import { useLang } from "../../contexts/LanguageContext";

const HOTEL_IMG = "data:image/jpeg;base64,";
const LOGO_IMG = "/logo.png";

import { C } from '../../lib/constants';

const S = {
  page: { minHeight:"100vh", background:C.bgPage, fontFamily:"'Segoe UI','Be Vietnam Pro',sans-serif", display:"flex", flexDirection:"column" },

  // Navbar
  nav: { background:C.white, borderBottom:`1px solid ${C.border}`, padding:"0 40px", height:70, display:"flex", alignItems:"center", justifyContent:"space-between", boxShadow:"0 1px 8px rgba(190,30,46,0.07)", position:"sticky", top:0, zIndex:100 },
  navLogoWrap: { display:"flex", alignItems:"center", cursor:"pointer", textDecoration:"none", background:"transparent", border:"none", padding:0 },
  navLogo: { height:78, width:"auto", objectFit:"contain", display:"block" },
  navLinks: { display:"flex", gap:28, listStyle:"none", margin:0, padding:0 },
  navLink: { fontSize:14, color:C.text, textDecoration: "none", fontWeight:500, cursor:"pointer", userSelect: "none" },
  navActions: { display:"flex", alignItems:"center", gap:10 },
  iconBtn: { width:36, height:36, borderRadius:"50%", border:"none", background:"transparent", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", padding:0 },
  btnDefault: { padding:"8px 18px", borderRadius:8, border:"none", background:"#F7F7F7", color:C.text, fontWeight:600, fontSize:13, cursor:"pointer", transition:"all 0.18s" },
  btnActive:  { padding:"8px 18px", borderRadius:8, border:"none", background:C.primary, color:"#fff", fontWeight:600, fontSize:13, cursor:"pointer", transition:"all 0.18s" },

  // Layout
  authWrap: { flex:1, display:"flex" },
  imgSide: { flex:"0 0 50%", position:"relative", overflow:"hidden", minHeight:"calc(100vh - 70px)" },
  hotelImg: { width:"100%", height:"100%", objectFit:"cover", display:"block" },
  imgOverlay: { position:"absolute", inset:0, background:"rgba(190,30,46,0.25)" },
  formSide: { flex:"0 0 50%", display:"flex", alignItems:"center", justifyContent:"center", padding:"48px 64px", background:C.bgPage },
  formBox: { width:"100%", maxWidth:390 },

  // Headings
  title: { fontSize:27, fontWeight:800, color:C.text, letterSpacing:1, textTransform:"uppercase", textAlign:"center", marginBottom:6 },
  sub: { fontSize:14, color:C.textMuted, textAlign:"center", marginBottom:26 },

  // Tabs
  tabs: { display:"flex", borderRadius:10, overflow:"hidden", border:`1.5px solid ${C.primary}`, marginBottom:26 },
  tab: (a) => ({ flex:1, padding:"10px 0", border:"none", background: a ? C.primary : C.white, color: a ? "#fff" : C.primary, fontWeight:600, fontSize:14, cursor:"pointer", transition:"all 0.18s" }),

  // Fields
  fg: { marginBottom:15 },
  fr: { display:"flex", gap:12, marginBottom:15 },
  label: { display:"block", fontSize:11, fontWeight:700, color:C.text, letterSpacing:1.2, textTransform:"uppercase", marginBottom:5 },
  input: { width:"100%", padding:"11px 14px", borderRadius:8, border:`1.5px solid ${C.inputBorder}`, background:C.inputBg, fontSize:14, color:C.text, outline:"none", boxSizing:"border-box", fontFamily:"inherit" },
  inputWrap: { position:"relative", display:"flex", alignItems:"center" },
  eyeBtn: { position:"absolute", right:10, background:"none", border:"none", cursor:"pointer", padding:4, display:"flex", alignItems:"center", justifyContent:"center", borderRadius:4, transition:"opacity 0.15s", opacity:0.5 },

  // Checkbox
  checkRow: { display:"flex", alignItems:"flex-start", gap:9, marginBottom:18, marginTop:4 },
  checkBox: { width:15, height:15, marginTop:2, accentColor:C.primary, cursor:"pointer", flexShrink:0 },
  checkLabel: { fontSize:13, color:C.textMuted, lineHeight:1.5 },
  redLink: { color:C.link, fontWeight:600, textDecoration:"none", cursor:"pointer" },

  // Submit
  submitBtn: { width:"100%", padding:"13px", borderRadius:8, border:"none", background:"#F7F7F7", color:C.text, fontWeight:700, fontSize:15, cursor:"pointer", letterSpacing:0.4, marginBottom:15, transition:"background 0.18s, color 0.18s" },
  submitBtnActive: { width:"100%", padding:"13px", borderRadius:8, border:"none", background:C.primary, color:"#fff", fontWeight:700, fontSize:15, cursor:"pointer", letterSpacing:0.4, marginBottom:15, transition:"background 0.18s, color 0.18s", boxShadow:"0 4px 16px rgba(190,30,46,0.28)" },
  bottomTxt: { textAlign:"center", fontSize:13, color:C.textMuted },

  // Divider & Social
  orRow: { display:"flex", alignItems:"center", gap:10, margin:"14px 0", color:C.textMuted, fontSize:13 },
  divLine: { flex:1, height:1, background:C.border },
  socialRow: { display:"flex", justifyContent:"center", gap:14, marginBottom:18 },
  socialBtn: { width:46, height:46, borderRadius:"50%", border:`1.5px solid ${C.border}`, background:C.white, display:"flex", alignItems:"center", justifyContent:"center", cursor:"pointer", fontSize:21, boxShadow:"0 2px 8px rgba(0,0,0,0.07)" },

  // Support
  supportRow: { display:"flex", justifyContent:"center", gap:10, marginTop:8 },
  supportBtn: { width:36, height:36, borderRadius:"50%", border:`1.5px solid ${C.border}`, background:C.white, display:"flex", alignItems:"center", justifyContent:"center", cursor:"pointer", fontSize:15, color:C.textMuted },
};

// ─── EYE ICON SVG ─────────────────────────────────────────────────────────────
const EyeOpen = () => (
  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#555" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/>
    <circle cx="12" cy="12" r="3"/>
  </svg>
);

const EyeOff = () => (
  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#555" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94"/>
    <path d="M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19"/>
    <line x1="1" y1="1" x2="23" y2="23"/>
  </svg>
);

// ─── SUBMIT BUTTON ────────────────────────────────────────────────────────────
const SubmitButton = ({ label, onClick, disabled }) => {
  const [hov, setHov] = useState(false);
  const isActive = hov && !disabled;
  return (
    <button
      style={isActive ? S.submitBtnActive : { ...S.submitBtn, opacity: disabled ? 0.5 : 1, cursor: disabled ? "not-allowed" : "pointer" }}
      onClick={onClick}
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      disabled={disabled}
    >
      {label}
    </button>
  );
};

// ─── SHARED: Hotel Image Side ─────────────────────────────────────────────────
const ImgSide = () => (
  <div style={S.imgSide}>
    <img src={HOTEL_IMG} alt="VLU Hotel Hub" style={S.hotelImg} />
    <div style={S.imgOverlay} />
  </div>
);

// ─── SHARED: Navbar ───────────────────────────────────────────────────────────
const AUTH_NAV_LINKS = [
  { tkey: "nav_home",           page: "home"           },
  { tkey: "nav_hotels",         page: "hotels"         },
  { tkey: "nav_mybookings",     page: "my-bookings"    },
  { tkey: "nav_become_partner", page: "become-partner" },
];

const Navbar = ({ active, setPage, user }) => {
  const { lang, toggleLang, t } = useLang();
  const [hov,     setHov]     = useState(null);
  const [hovLink, setHovLink] = useState(null);
  const [isDark, setIsDark]   = useState(() => localStorage.getItem("theme") === "dark");

  const isPartner = user?.userType === "PARTNER";
  const navLinks = isPartner
    ? [
        { tkey: "nav_home",       page: "partner-dashboard" },
        { tkey: "nav_hotels",     page: "partner-hotels"    },
        { tkey: "nav_mybookings", page: "my-bookings"       },
      ]
    : AUTH_NAV_LINKS;

  useEffect(() => {
    if (isDark) {
      document.documentElement.style.filter = "invert(0.92) hue-rotate(180deg) contrast(0.9)";
      document.documentElement.style.background = "#fff";
      
      let style = document.getElementById("dark-mode-fixes");
      if (!style) {
        style = document.createElement("style");
        style.id = "dark-mode-fixes";
        style.innerHTML = `
          img, video, iframe {
            filter: contrast(1.11) hue-rotate(180deg) invert(1) !important;
          }
          input { background-color: transparent !important; }
        `;
        document.head.appendChild(style);
      }
    } else {
      document.documentElement.style.filter = "";
      document.documentElement.style.background = "";
      const style = document.getElementById("dark-mode-fixes");
      if (style) style.remove();
    }
  }, [isDark]);

  const toggleDark = () => {
    setIsDark(p => {
      const next = !p;
      localStorage.setItem("theme", next ? "dark" : "light");
      return next;
    });
  };

  const btnStyle = (key) => {
    const isActive = active === key;
    const isHov    = hov === key;
    return {
      ...S.btnDefault,
      background: (isActive || isHov) ? C.primary : "#F7F7F7",
      color:      (isActive || isHov) ? "#fff"     : C.text,
      transition: "background 0.15s ease, color 0.15s ease",
    };
  };

  return (
  <nav style={S.nav}>
    <div style={S.navLogoWrap} onClick={() => setPage("home")}>
      <img src={LOGO_IMG} alt="VLU Hotel Hub" style={S.navLogo} />
    </div>
    <ul style={{ ...S.navLinks, gap: 28 }}>
      {navLinks.map(({ tkey, page }) => {
        const isActive = active === page;
        const isHov    = hovLink === page;
        return (
          <li key={page}>
            <a
              style={{
                ...S.navLink,
                color: isActive || isHov ? C.primary : C.text,
                fontWeight: isActive ? 700 : 500,
                borderBottom: isActive || isHov ? `2px solid ${C.primary}` : "2px solid transparent",
                paddingBottom: 3,
                cursor: "pointer",
                transition: "color 0.15s ease, border-color 0.15s ease",
              }}
              onClick={() => setPage(page)}
              onMouseEnter={() => setHovLink(page)}
              onMouseLeave={() => setHovLink(null)}
            >{t(tkey)}</a>
          </li>
        );
      })}
    </ul>
    <div style={{ ...S.navActions, gap: 10 }}>
      <button style={S.iconBtn} onClick={toggleDark} title={isDark ? "Chế độ sáng" : "Chế độ tối"}>
        {isDark ? (
          <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#1a1a1a" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <circle cx="12" cy="12" r="5"></circle><line x1="12" y1="1" x2="12" y2="3"></line><line x1="12" y1="21" x2="12" y2="23"></line><line x1="4.22" y1="4.22" x2="5.64" y2="5.64"></line><line x1="18.36" y1="18.36" x2="19.78" y2="19.78"></line><line x1="1" y1="12" x2="3" y2="12"></line><line x1="21" y1="12" x2="23" y2="12"></line><line x1="4.22" y1="19.78" x2="5.64" y2="18.36"></line><line x1="18.36" y1="5.64" x2="19.78" y2="4.22"></line>
          </svg>
        ) : (
          <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#1a1a1a" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"></path>
          </svg>
        )}
      </button>
      <button
        style={{ ...S.iconBtn, gap: 4, fontSize: 12, fontWeight: 800, padding: "6px 10px" }}
        onClick={toggleLang}
        title={lang === "vi" ? "Switch to English" : "Chuyển sang Tiếng Việt"}
      >
        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <circle cx="12" cy="12" r="10"/><line x1="2" y1="12" x2="22" y2="12"/>
          <path d="M12 2a15.3 15.3 0 0 1 4 10 15.3 15.3 0 0 1-4 10 15.3 15.3 0 0 1-4-10 15.3 15.3 0 0 1 4-10z"/>
        </svg>
        {lang === "vi" ? "EN" : "VI"}
      </button>
      <button
        style={btnStyle("login")}
        onClick={() => setPage("login")}
        onMouseEnter={() => setHov("login")}
        onMouseLeave={() => setHov(null)}
      >{t("nav_login")}</button>
      <button
        style={{ ...btnStyle("register"), borderRadius: 8 }}
        onClick={() => setPage("register")}
        onMouseEnter={() => setHov("register")}
        onMouseLeave={() => setHov(null)}
      >{t("nav_register")}</button>
    </div>
  </nav>
  );
};


// ─── ACTION BUTTON (gray default → primary on hover) ─────────────────────────
const ActionBtn = ({ children, onClick, disabled = false, style = {} }) => {
  const [hov, setHov] = useState(false);
  const active = hov && !disabled;
  return (
    <button
      onClick={onClick}
      disabled={disabled}
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      style={{
        background: disabled ? "#e8e8e8" : active ? C.primary : "#F7F7F7",
        color:      disabled ? "#aaa"    : active ? "#fff"     : "#1a1a1a",
        border: "none",
        borderRadius: 10,
        padding: "13px 28px",
        fontSize: 14,
        fontWeight: 700,
        cursor: disabled ? "not-allowed" : "pointer",
        transition: "background 0.15s ease, color 0.15s ease",
        fontFamily: "inherit",
        ...style,
      }}
    >
      {children}
    </button>
  );
};

export { HOTEL_IMG, LOGO_IMG, C, S, EyeOpen, EyeOff, SubmitButton, ImgSide, Navbar, ActionBtn };
